```
  private createResponse(result: Result, wasCached: boolean): ProviderResponse {
    console.log(`Latency: ${result.latencyMs}`);
    if (!result.latencyMs) {
      throw new Error("Oops!");
    }
    return {
      cached: wasCached,
      output: JSON.stringify(result.output, null, 2),
      latencyMs: result.latencyMs,
      tokenUsage: {
        prompt: result.usage.input,
        cached: result.usage.cacheRead,
        completion: result.usage.output,
      },
    };
  }
```
